// buildFBEventEnrichmentParams builds the Facebook API URL query parameters for event-time
// attribution enrichment. It uses request.RequestID as event_id (unique per event) and
// kochava_device_id as install_id (unique per install).
func buildFBEventEnrichmentParams(request *structs.WatsonRequest) string {
	deviceID := request.Identifiers["kochava_device_id"]
	params := ""

	if request.FBAttributionDetails != nil {
		details := request.FBAttributionDetails
		params += "&is_fb=true"
		params += "&event_id=" + url.QueryEscape(request.RequestID)
		params += "&install_id=" + url.QueryEscape(deviceID)

		if details.InstallTime > 0 {
			params += fmt.Sprintf("&install_time=%d", details.InstallTime)
		}

		// attribution_sources: JSON array with previous FB claim proof.
		// Only send when AuditingToken is non-empty. GPIR-attributed devices
		// (facebook-install-referrer module) never receive an auditing_token from
		// Meta because GPIR works by decrypting the Google Play install referrer
		// locally — Meta's SAN API is never called, so no token is ever issued.
		// Sending attribution_sources with source_auditing_token="" causes Meta to
		// treat it as a failed validation rather than ignoring the field, which
		// reduces the claim win rate for GPIR-attributed devices.
		// Ref: https://app.asana.com/1/8559678460204/project/1203451271303566/task/1214509671208635
		if details.AdID != "" && details.AuditingToken != "" {
			attrSource := []map[string]interface{}{
				{
					"source_ad_id":         details.AdID,
					"source_event_time":     details.ClickTime,
					"source_auditing_token": details.AuditingToken,
				},
			}
			if attrSourceJSON, err := json.Marshal(attrSource); err == nil {
				params += "&attribution_sources=" + url.QueryEscape(string(attrSourceJSON))
			}
		}

		if details.GoogleInstallReferrer != "" {
			params += "&google_install_referrer=" + url.QueryEscape(details.GoogleInstallReferrer)
		}
		if details.MetaInstallReferrer != "" {
			params += "&meta_install_referrer=" + url.QueryEscape(details.MetaInstallReferrer)
		}
	} else if request.IsFB {
		// Device is FB-attributed but no details available (restricted cache expired after 30-day TTL)
		params += "&is_fb=true"
		params += "&event_id=" + url.QueryEscape(request.RequestID)
		params += "&install_id=" + url.QueryEscape(deviceID)
	} else {
		params += "&is_fb=false"
	}

	return params
}
