func Test_buildFBEventEnrichmentParams_EventID_UsesRequestID(t *testing.T) {
	// event_id must be the Watson request_id, NOT kochava_device_id
	// Regression test for bug found by QA (Adam Alverez, Mar 2026):
	// event_id was incorrectly set to kochava_device_id instead of request_id.
	request := &structs.WatsonRequest{
		IsFB:      true,
		RequestID: "20260330231556KD6LPBHAAN145909008",
		Identifiers: map[string]string{
			"kochava_device_id": "QAKDID20260320194638121808055",
		},
		FBAttributionDetails: &structs.FBAttributionDetails{
			AdID:          "67890",
			ClickTime:     1734958800,
			AuditingToken: "token_abc",
		},
	}

	params := buildFBEventEnrichmentParams(request)

	assert.Contains(t, params, "event_id=20260330231556KD6LPBHAAN145909008",
		"event_id should be the request_id, not kochava_device_id")
	assert.Contains(t, params, "install_id=QAKDID20260320194638121808055",
		"install_id should be kochava_device_id")
	assert.NotContains(t, params, "event_id=QAKDID20260320194638121808055",
		"event_id must NOT equal kochava_device_id")
}

