func Test_buildFBEventEnrichmentParams_RestrictedCacheMiss_UsesRequestID(t *testing.T) {
	// Restricted path: is_fb=true but no FBAttributionDetails (Redis cache miss)
	// event_id should still use RequestID, not device ID
	request := &structs.WatsonRequest{
		IsFB:                 true,
		RequestID:            "req-restricted-456",
		FBAttributionDetails: nil,
		Identifiers: map[string]string{
			"kochava_device_id": "kdid-restricted-789",
		},
	}

	params := buildFBEventEnrichmentParams(request)

	assert.Contains(t, params, "&is_fb=true")
	assert.Contains(t, params, "event_id=req-restricted-456",
		"event_id should use RequestID even on cache miss path")
	assert.Contains(t, params, "install_id=kdid-restricted-789")
	assert.NotContains(t, params, "event_id=kdid-restricted-789",
		"event_id must NOT equal kochava_device_id on cache miss path")
}

