func Test_buildFBEventEnrichmentParams_GPIR_EmptyAuditingToken_NoAttributionSources(t *testing.T) {
	// GPIR-attributed devices (facebook-install-referrer module) never receive an
	// auditing_token from Meta — GPIR works by decrypting the Google Play install
	// referrer locally and never calls Meta's SAN API. As a result AuditingToken
	// is stored as "" in Redis.
	//
	// Sending attribution_sources with source_auditing_token="" causes Meta to treat
	// it as a failed validation rather than ignoring the field, which reduces the
	// claim win rate. attribution_sources must NOT be sent when AuditingToken is empty.
	//
	// Ref: https://app.asana.com/1/8559678460204/project/1203451271303566/task/1214509671208635
	request := &structs.WatsonRequest{
		IsFB:      true,
		RequestID: "req-gpir-event",
		Identifiers: map[string]string{
			"kochava_device_id": "kdid-gpir-device",
		},
		FBAttributionDetails: &structs.FBAttributionDetails{
			AdID:              "123456",   // present — GPIR has ad_id from utm_content
			ClickTime:         1709900000,
			AuditingToken:     "",         // empty — GPIR never calls Meta's SAN API
			InstallTime:       1709800000,
			AttributionMethod: "GPIR",
		},
	}

	params := buildFBEventEnrichmentParams(request)

	assert.Contains(t, params, "&is_fb=true",
		"is_fb should still be true for GPIR-attributed devices")
	assert.Contains(t, params, "event_id=req-gpir-event",
		"event_id should still be sent")
	assert.Contains(t, params, "install_id=kdid-gpir-device",
		"install_id should still be sent")
	assert.NotContains(t, params, "attribution_sources",
		"attribution_sources must NOT be sent when AuditingToken is empty (GPIR case)")
	assert.NotContains(t, params, "source_auditing_token",
		"source_auditing_token must never appear with an empty value")
}
